Editó: /Users/josegomezj/home/rcw/go_memory/infrastructure/container.go, /Users/josegomezj/home/rcw/go_memory/adapters/primary/cli/dispatcher.go, /Users/josegomezj/home/rcw/go_memory/adapters/primary/cli/cli.go, /Users/josegomezj/home/rcw/go_memory/tests/integration/plugin_integration_test.go. Comandos: echo "=== plugin_integration_test.go completo ==="; cat tests/integration/plugin_integration_test.go; echo "=== archivos del paquete mcp ==="; ls -1 adapters/primary/mcp/; rm -v adapters/primary/cli/cmd_serve.go && rm -rvf adapters/primary/mcp/ && echo "--- borrados ---"; echo "=== grep residual de mcp legacy/serve ===" && grep -rn "primary/mcp\|CmdServe\|mem serve\|9735" adapters application infrastructure tests 2>/dev/null | grep -v "setup" ; echo "=== build ===" && go build ./... 2>&1 | head -30 && echo "BUILD_EXIT=$?"; go test ./tests/integration/ ./infrastructure/... ./adapters/primary/cli/... 2>&1 | tail -25; python3 - <<'PY'
src = open('docs/blueprint.html', encoding='utf-8').read()

# 1) Quitar envoltorio de cabecera: desde <!DOCTYPE ...> hasta antes de <title>
title_idx = src.index('<title>')
src = src[title_idx:]

# 2) Quitar cierre </body></html> final
for tag in ('</html>', '</body>'):
    i = src.rfind(tag)
    if i != -1:
        src = src[:i] + src[i+len(tag):]
src = src.rstrip() + '\n'

# 3) Inyectar overrides data-theme tras la media query light, para que el
#    toggle del visor de Artifacts gane en ambas direcciones.
anchor = """  @media (prefers-color-scheme: light){
    :root{
      --bg:#f4f7fb; --bg2:#eef2f8; --card:#ffffff; --card2:#f7f9fc;
      --line:#dde5ee; --line2:#c9d5e3;
      --tx:#16202c; --tx2:#425163; --tx3:#6f8298;
    }
  }"""
assert anchor in src, "no se encontró el ancla de la media query light"
extra = anchor + """
  :root[data-theme="light"]{
    --bg:#f4f7fb; --bg2:#eef2f8; --card:#ffffff; --card2:#f7f9fc;
    --line:#dde5ee; --line2:#c9d5e3;
    --tx:#16202c; --tx2:#425163; --tx3:#6f8298;
  }
  :root[data-theme="dark"]{
    --bg:#0d1117; --bg2:#131a24; --card:#161f2b; --card2:#1c2836;
    --line:#26313f; --line2:#324152;
    --tx:#e7edf5; --tx2:#9fb0c3; --tx3:#6f8298;
  }"""
src = src.replace(anchor, extra, 1)

open('docs/blueprint-artifact.html', 'w', encoding='utf-8').write(src)
print("OK -> docs/blueprint-artifact.html")
print("primeras líneas:")
print('\n'.join(src.splitlines()[:3]))
print("...")
print('\n'.join(src.splitlines()[-3:]))
PY
